function Prog({step}){
  if(step<1||step>5)return null;
  const labels=["LGPD","Dados","Perfil","Áudio","Currículo"];
  return(
    <div style={{background:`linear-gradient(135deg,${B1},${B2})`,padding:"10px 20px",borderBottom:"1px solid rgba(255,255,255,.1)"}}>
      <div style={{display:"flex",maxWidth:560,margin:"0 auto"}}>
        {labels.map((l,i)=>{
          const idx=i+1,done=idx<step,active=idx===step;
          return(
            <div key={i} style={{flex:1,display:"flex",flexDirection:"column",alignItems:"center",position:"relative"}}>
              {i<labels.length-1&&<div style={{position:"absolute",top:10,left:"50%",width:"100%",height:2,background:done?B4:"rgba(255,255,255,.15)",zIndex:0}}/>}
              <div style={{width:21,height:21,borderRadius:"50%",border:`2px solid ${active||done?B4:"rgba(255,255,255,.25)"}`,background:active?B4:"transparent",display:"flex",alignItems:"center",justifyContent:"center",fontSize:9,fontWeight:700,color:active?"#fff":done?B4:"rgba(255,255,255,.4)",zIndex:1}}>{done?"✓":idx}</div>
              <div style={{fontSize:8.5,color:active||done?"rgba(255,255,255,.65)":"rgba(255,255,255,.3)",marginTop:3,textTransform:"uppercase",letterSpacing:"0.04em"}}>{l}</div>
            </div>
          );
        })}
      </div>
    </div>
  );
}

function Card({children,style={}}){return <div style={{background:"#fff",borderRadius:16,boxShadow:"0 4px 20px rgba(0,62,138,.08)",padding:24,border:`1px solid ${G200}`,...style}}>{children}</div>;}

function Btn({children,onClick,sec,sm}){
  if(sec)return <button onClick={onClick} style={{cursor:"pointer",border:`1.5px solid ${G200}`,background:"#fff",color:G600,fontSize:13,fontWeight:700,padding:"9px 18px",borderRadius:9}}>{children}</button>;
  return <button onClick={onClick} style={{cursor:"pointer",border:"none",background:`linear-gradient(135deg,${B2},${B3})`,color:"#fff",fontSize:sm?12:13.5,fontWeight:700,padding:sm?"7px 13px":"11px 22px",borderRadius:9,boxShadow:"0 4px 14px rgba(0,93,181,.3)"}}>{children}</button>;
}

