function P2({onNext,onBack}){
  const [f,setF]=useState({nome:"",email:"",tel:"",cidade:"",uf:""});
  const [e,setE]=useState({});
  const UFS=["AC","AL","AM","AP","BA","CE","DF","ES","GO","MA","MG","MS","MT","PA","PB","PE","PI","PR","RJ","RN","RO","RR","RS","SC","SE","SP","TO"];
  const up=(k,v)=>setF(p=>({...p,[k]:v}));
  function go(){
    const err={};
    if(!f.nome||f.nome.trim().length<3)err.nome="Obrigatório";
    if(!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(f.email))err.email="E-mail inválido";
    if(!f.tel||f.tel.trim().length<8)err.tel="Obrigatório";
    if(!f.cidade||f.cidade.trim().length<2)err.cidade="Obrigatório";
    if(!f.uf)err.uf="Selecione";
    setE(err);
    if(!Object.keys(err).length)onNext(f);
  }
  const inp=(label,k,type="text",opts)=>(
    <div style={{display:"flex",flexDirection:"column",gap:4}}>
      <label style={{fontSize:12,fontWeight:600,color:G700}}>{label} <span style={{color:B3}}>*</span></label>
      {opts
        ?<select value={f[k]} onChange={ev=>up(k,ev.target.value)} style={{border:`1.5px solid ${e[k]?RED:G200}`,borderRadius:9,padding:"9px 11px",fontSize:13,color:G800,background:G50,outline:"none"}}><option value="">Selecione...</option>{opts.map(o=><option key={o}>{o}</option>)}</select>
        :<input type={type} value={f[k]} onChange={ev=>up(k,ev.target.value)} style={{border:`1.5px solid ${e[k]?RED:G200}`,borderRadius:9,padding:"9px 11px",fontSize:13,color:G800,background:G50,outline:"none"}}/>
      }
      {e[k]&&<span style={{fontSize:11,color:RED}}>{e[k]}</span>}
    </div>
  );
  return(
    <div style={{maxWidth:700,margin:"0 auto",padding:"28px 16px"}}>
      <div style={{textAlign:"center",marginBottom:20}}>
        <span style={{background:BP,color:B2,fontSize:10.5,fontWeight:700,padding:"4px 12px",borderRadius:16,border:`1px solid ${B100}`,letterSpacing:"0.1em",textTransform:"uppercase"}}>👤 Etapa 2 de 5</span>
        <h1 style={{fontSize:26,fontWeight:800,color:B1,marginTop:10,marginBottom:6}}>Seus Dados</h1>
        <p style={{color:G600,fontSize:13}}>Preencha corretamente — usaremos para contato.</p>
      </div>
      <Card>
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:14,marginBottom:8}}>
          <div style={{gridColumn:"1/-1"}}>{inp("Nome Completo","nome")}</div>
          {inp("E-mail","email","email")}
          {inp("Telefone/WhatsApp","tel","tel")}
          {inp("Cidade","cidade")}
          {inp("Estado","uf","text",UFS)}
        </div>
        <div style={{display:"flex",justifyContent:"space-between",marginTop:18}}>
          <Btn sec onClick={onBack}>← Voltar</Btn>
          <Btn onClick={go}>Continuar →</Btn>
        </div>
      </Card>
    </div>
  );
}

// ALTERAÇÃO: grid de perfis (Águia/Lobo/Golfinho/Tubarão) REMOVIDO da etapa 3
// Aparece agora apenas na tela de confirmação final (P6)
function P3({onNext,onBack}){
  const [qi,setQi]=useState(0);
  const [ans,setAns]=useState({});
  const [err,setErr]=useState(false);
  const q=QS[qi];
  function nav(d){
    if(d===1&&!ans[q.id]){setErr(true);return;}
    setErr(false);
    if(d===-1&&qi===0){onBack();return;}
    if(d===1&&qi===QS.length-1){onNext(ans);return;}
    setQi(qi+d);
  }
  return(
    <div style={{maxWidth:700,margin:"0 auto",padding:"28px 16px"}}>
      <div style={{textAlign:"center",marginBottom:20}}>
        <span style={{background:BP,color:B2,fontSize:10.5,fontWeight:700,padding:"4px 12px",borderRadius:16,border:`1px solid ${B100}`,letterSpacing:"0.1em",textTransform:"uppercase"}}>🧠 Etapa 3 de 5</span>
        <h1 style={{fontSize:26,fontWeight:800,color:B1,marginTop:10,marginBottom:6}}>Perfil Comportamental</h1>
        <p style={{color:G600,fontSize:13}}>Escolha a palavra que melhor representa você.</p>
      </div>
      <Card>
        <div style={{display:"flex",justifyContent:"space-between",marginBottom:6}}>
          <span style={{fontSize:12,color:G400}}>Questão <strong style={{color:B1}}>{qi+1}</strong> de <strong style={{color:B1}}>{QS.length}</strong></span>
          <span style={{fontSize:12,color:G400}}>Respondidas: {Object.keys(ans).length}</span>
        </div>
        <div style={{height:4,background:G200,borderRadius:2,marginBottom:16,overflow:"hidden"}}>
          <div style={{height:"100%",width:`${((qi+1)/QS.length)*100}%`,background:`linear-gradient(90deg,${B2},${B4})`,transition:"width .4s"}}/>
        </div>
        <p style={{fontSize:14,fontWeight:700,color:B1,marginBottom:12}}>Q{qi+1}: Qual palavra melhor representa você?</p>
        {q.o.map(o=>{
          const sel=ans[q.id]===o.l;
          return(
            <div key={o.l} onClick={()=>{setAns(p=>({...p,[q.id]:o.l}));setErr(false);}} style={{border:`1.5px solid ${sel?B2:G200}`,borderRadius:9,padding:"11px 13px",display:"flex",alignItems:"center",gap:10,cursor:"pointer",background:sel?BP:G50,marginBottom:7,transition:"all .15s"}}>
              <div style={{width:26,height:26,borderRadius:6,background:sel?B2:B1,display:"flex",alignItems:"center",justifyContent:"center",fontWeight:800,fontSize:12,color:sel?"#fff":B4,flexShrink:0}}>{o.l}</div>
              <span style={{fontSize:13,fontWeight:600,color:G700}}>{o.t}</span>
            </div>
          );
        })}
        {err&&<p style={{color:RED,fontSize:11,marginTop:4}}>Selecione uma alternativa.</p>}
        <div style={{display:"flex",justifyContent:"space-between",marginTop:18}}>
          <Btn sec onClick={()=>nav(-1)}>{qi===0?"← Voltar":"← Anterior"}</Btn>
          <Btn onClick={()=>nav(1)}>{qi===QS.length-1?"Finalizar Etapa →":"Próxima →"}</Btn>
        </div>
      </Card>
    </div>
  );
}

