function Modal({c,onClose}){
  const [ascore,setAscore]=useState(c.as);
  const top=Object.entries({A:c.A,B:c.B,C:c.C,D:c.D}).sort((a,b)=>b[1]-a[1])[0];
  return(
    <div style={{position:"fixed",top:0,left:0,right:0,bottom:0,background:"rgba(0,0,0,.5)",display:"flex",alignItems:"center",justifyContent:"center",zIndex:1000,padding:16}} onClick={e=>{if(e.target===e.currentTarget)onClose();}}>
      <div style={{background:"#fff",borderRadius:16,padding:"24px",maxWidth:520,width:"100%",maxHeight:"80vh",overflowY:"auto"}}>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:16}}>
          <div>
            <h2 style={{fontWeight:800,color:B1,fontSize:"1.1rem"}}>{c.nm}</h2>
            <div style={{fontSize:11,color:G400,marginTop:2}}>{c.id} · {c.pr} · {c.dt}</div>
          </div>
          <button onClick={onClose} style={{background:"none",border:"none",color:G400,fontSize:18,cursor:"pointer",lineHeight:1}}>✕</button>
        </div>
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8,marginBottom:14}}>
          {[[c.em,"📧"],[c.tel,"📞"],[`${c.ci} – ${c.uf}`,"📍"],[c.st,"📌"]].map(([v,ic])=>(
            <div key={ic} style={{background:G50,borderRadius:8,padding:"8px 11px",fontSize:12,color:G700}}>{ic} {v}</div>
          ))}
        </div>
        <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:8,marginBottom:14}}>
          {[["Comportamental",c.sc,"/100"],["Currículo",c.cs,"/100"],["Total",c.tt,"/100"]].map(([l,v,s])=>(
            <div key={l} style={{background:G50,borderRadius:8,padding:"10px",textAlign:"center",border:`1px solid ${G200}`}}>
              <div style={{fontSize:10,color:G400,textTransform:"uppercase",fontWeight:700,marginBottom:4}}>{l}</div>
              <div style={{fontSize:20,fontWeight:800,color:scColor(v)}}>{v}</div>
              <div style={{fontSize:10,color:G400}}>{s}</div>
            </div>
          ))}
        </div>
        <div style={{background:BP,borderRadius:10,padding:"12px 14px",marginBottom:14,border:`1px solid ${B100}`}}>
          <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:8}}>
            <span style={{fontSize:12,fontWeight:700,color:B1}}>🎵 Score de Áudio</span>
            <span style={{fontSize:11,fontWeight:700,color:B2}}>{ascore.toFixed(1)} / 10</span>
          </div>
          <input type="range" min="0" max="10" step="0.1" value={ascore} onChange={e=>setAscore(parseFloat(e.target.value))} style={{width:"100%",accentColor:B2}}/>
          <div style={{fontSize:10,color:G400,marginTop:4}}>Ajuste manual da nota de áudio</div>
        </div>
        <div style={{background:G50,borderRadius:10,padding:"12px 14px",border:`1px solid ${G200}`}}>
          <div style={{fontWeight:700,color:B1,fontSize:12,marginBottom:8}}>Perfil Comportamental</div>
          <div style={{display:"flex",gap:8,flexWrap:"wrap"}}>
            {Object.entries({A:c.A,B:c.B,C:c.C,D:c.D}).map(([k,v])=>(
              <div key={k} style={{flex:1,minWidth:80,background:k===top[0]?B1:G200,borderRadius:8,padding:"8px",textAlign:"center"}}>
                <div style={{fontSize:16}}>{PF[k].e}</div>
                <div style={{fontWeight:800,fontSize:16,color:k===top[0]?"#fff":G700}}>{v}</div>
                <div style={{fontSize:10,color:k===top[0]?B4:G400,fontWeight:700}}>{PF[k].n}</div>
              </div>
            ))}
          </div>
        </div>
        <div style={{display:"flex",gap:8,marginTop:16}}>
          <Btn sec onClick={onClose}>Fechar</Btn>
          <Btn>💾 Salvar Alterações</Btn>
        </div>
      </div>
    </div>
  );
}

